                        .font(.body)
                        .fontWeight(.semibold)
                }

                Spacer()

                VStack(alignment: .leading) {
                    Text("QQQ vs EMA20")
                        .font(.caption)
                        .foregroundColor(.gray)
                    Text(String(format: "%.2f%%", regime.qqq_vs_ema20_pct))
                        .font(.body)
                        .fontWeight(.semibold)
                }

                Spacer()

                VStack(alignment: .leading) {
                    Text("VIX")
