    let status: ScannerStatus?
    let logs: [String]
    let onScanTapped: () -> Void
    @State private var logsExpanded = false

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            // Scanner Status
            if let status = status {
                HStack {
                    VStack(alignment: .leading, spacing: 4) {
                        Text("Scanner Status")
                            .font(.headline)
                            .fontWeight(.bold)
