                            .font(.caption)
                            .foregroundColor(.gray)
                    }

                    Spacer()

                    Button(action: onScanTapped) {
                        Text("Scan Now")
                            .font(.caption)
                            .fontWeight(.semibold)
                            .padding(8)
                            .background(Color.blue)
                            .foregroundColor(.white)
                            .cornerRadius(4)
                    }
                }
                .padding(8)
                .background(Color(.controlBackgroundColor))
                .cornerRadius(8)
            }

            // Logs
            VStack(alignment: .leading, spacing: 8) {
                Button(action: { logsExpanded.toggle() }) {
                    HStack {
                        Text("Live Logs")
                            .font(.headline)
                            .fontWeight(.bold)
                        Spacer()
                        Image(systemName: logsExpanded ? "chevron.up" : "chevron.down")
                    }
                }

                if logsExpanded {
                    ScrollView {
                        VStack(alignment: .leading, spacing: 2) {
                            ForEach(logs, id: \.self) { log in
                                Text(log)
                                    .font(.system(.caption, design: .monospaced))
                                    .foregroundColor(.gray)
                            }
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                    }
                    .frame(maxHeight: 200)
                    .padding(8)
                    .background(Color.black.opacity(0.05))
                    .cornerRadius(4)
                }
            }
            .padding(8)
            .background(Color(.controlBackgroundColor))
            .cornerRadius(8)
        }
        .padding()
    }
}

// MARK: - Settings View

struct SettingsView: View {
    @ObservedObject var api: TradingBotAPI
    @Environment(\.presentationMode) var presentationMode
    @State private var vpsIP = "localhost"
    @State private var vpsPort = "5000"

    var body: some View {
        VStack(spacing: 16) {
            Text("Settings")
                .font(.headline)
                .fontWeight(.bold)

            VStack(alignment: .leading, spacing: 8) {
                Text("VPS IP Address")
                    .font(.caption)
                    .foregroundColor(.gray)
                TextField("localhost", text: $vpsIP)
                    .textFieldStyle(.roundedBorder)
            }

            VStack(alignment: .leading, spacing: 8) {
                Text("VPS Port")
                    .font(.caption)
                    .foregroundColor(.gray)
                TextField("5000", text: $vpsPort)
                    .textFieldStyle(.roundedBorder)
            }

            HStack(spacing: 12) {
                Button("Cancel") {
                    presentationMode.wrappedValue.dismiss()
                }
                .keyboardShortcut(.cancelAction)

                Button("Save") {
                    if let port = Int(vpsPort) {
                        api.setVPSAddress(ip: vpsIP, port: port)
                        api.testConnection()
                    }
                    presentationMode.wrappedValue.dismiss()
                }
                .keyboardShortcut(.defaultAction)
            }

            Spacer()
        }
        .padding()
        .frame(width: 300)
    }
}

